import time
import threading
from collections import deque, defaultdict

try:
    import cv2
    import numpy as np
    VISION_AVAILABLE = True
except ImportError:
    VISION_AVAILABLE = False
    print("OpenCV/NumPy not available - fallback triggered")

try:
    import mediapipe as mp
    MEDIAPIPE_AVAILABLE = True
except ImportError:
    MEDIAPIPE_AVAILABLE = False
    print("MediaPipe not available - using basic fallback")

class VisionEmotionLink:
    def __init__(self, core, voice=None):
        self.core = core
        self.voice = voice
        self.pattern_memory = {}
        self.emotion_history = deque(maxlen=50)
        self.last_observation_time = 0
        self.observation_cooldown = 5.0

        self.face_cascade = None
        self.mp_face_detection = None
        self.mp_drawing = None
        self._initialize_face_detection()

        self.current_emotions = defaultdict(float)
        self.emotion_thresholds = {
            'happy': 0.3,
            'sad': 0.3,
            'angry': 0.4,
            'surprised': 0.3,
            'neutral': 0.2
        }

    def _initialize_face_detection(self):
        if VISION_AVAILABLE:
            try:
                self.face_cascade = cv2.CascadeClassifier(
                    cv2.data.haarcascades + 'haarcascade_frontalface_default.xml')
            except Exception as e:
                print(f"[VisionLink] OpenCV cascade error: {e}")

        if MEDIAPIPE_AVAILABLE:
            try:
                self.mp_face_detection = mp.solutions.face_detection.FaceDetection(
                    model_selection=0, min_detection_confidence=0.5)
                self.mp_drawing = mp.solutions.drawing_utils
            except Exception as e:
                print(f"[VisionLink] MediaPipe init error: {e}")

    def process_frame(self, frame):
        if not VISION_AVAILABLE or frame is None:
            return None

        try:
            faces = self._detect_faces(frame)
            if faces:
                emotions = self._analyze_emotions(frame, faces)
                if emotions:
                    self._process_emotions(emotions, frame.shape)
                    if self._should_make_observation():
                        self._make_contextual_observation(emotions)
                return emotions
        except Exception as e:
            print(f"[VisionLink] Frame error: {e}")
        return None

    def _detect_faces(self, frame):
        faces = []
        if self.mp_face_detection:
            try:
                rgb_frame = cv2.cvtColor(frame, cv2.COLOR_BGR2RGB)
                results = self.mp_face_detection.process(rgb_frame)
                if results.detections:
                    h, w, _ = frame.shape
                    for detection in results.detections:
                        bbox = detection.location_data.relative_bounding_box
                        x = int(bbox.xmin * w)
                        y = int(bbox.ymin * h)
                        width = int(bbox.width * w)
                        height = int(bbox.height * h)
                        faces.append((x, y, width, height))
            except Exception as e:
                print(f"[VisionLink] MediaPipe detection error: {e}")

        if not faces and self.face_cascade:
            try:
                gray = cv2.cvtColor(frame, cv2.COLOR_BGR2GRAY)
                detected = self.face_cascade.detectMultiScale(gray, scaleFactor=1.1, minNeighbors=5)
                faces = [(x, y, w, h) for (x, y, w, h) in detected]
            except Exception as e:
                print(f"[VisionLink] OpenCV fallback error: {e}")

        return faces

    def _analyze_emotions(self, frame, faces):
        emotions = []
        for (x, y, w, h) in faces:
            roi = frame[y:y+h, x:x+w]
            data = self._simple_emotion_analysis(roi)
            if data:
                data['bbox'] = (x, y, w, h)
                emotions.append(data)
        return emotions

    def _simple_emotion_analysis(self, roi):
        if roi.size == 0:
            return None
        try:
            gray = cv2.cvtColor(roi, cv2.COLOR_BGR2GRAY)
            h, w = gray.shape
            upper = gray[:h//2, :]
            lower = gray[h//2:, :]
            ub = np.mean(upper)
            lb = np.mean(lower)
            ratio = lb / (ub + 1)
            expr = {'neutral': 0.5}

            if ratio > 1.1:
                expr['happy'] = min(0.8, (ratio - 1.0) * 2)
                expr['neutral'] = 1.0 - expr['happy']
            elif ratio < 0.9:
                expr['sad'] = min(0.6, (1.0 - ratio) * 1.5)
                expr['neutral'] = 1.0 - expr['sad']

            edges = cv2.Canny(gray, 50, 150)
            density = np.sum(edges > 0) / edges.size
            if density > 0.1:
                expr['angry' if density > 0.15 else 'surprised'] = min(0.7, density * 3)

            total = sum(expr.values())
            if total > 0:
                expr = {k: v/total for k, v in expr.items()}

            return {
                'expressions': expr,
                'intensity': max(expr.values()),
                'dominant_emotion': max(expr, key=expr.get)
            }
        except Exception as e:
            print(f"[VisionLink] Emotion analysis error: {e}")
            return None

    def _process_emotions(self, emotions, shape):
        for data in emotions:
            expressions = data.get('expressions', {})
            intensity = data.get('intensity', 0.5)
            for emotion, confidence in expressions.items():
                if confidence > self.emotion_thresholds.get(emotion, 0.3):
                    self.current_emotions[emotion] = max(
                        self.current_emotions[emotion], confidence * intensity)

        self.emotion_history.append({
            'timestamp': time.time(),
            'emotions': dict(self.current_emotions),
            'frame_shape': shape
        })

        decay = 0.95
        for k in self.current_emotions:
            self.current_emotions[k] *= decay

    def _should_make_observation(self):
        now = time.time()
        if now - self.last_observation_time < self.observation_cooldown:
            return False
        max_em = max(self.current_emotions.items(), key=lambda x: x[1], default=('neutral', 0))
        if max_em[1] > 0.6:
            return True
        if len(self.emotion_history) >= 2:
            a = self.emotion_history[-1]['emotions']
            b = self.emotion_history[-2]['emotions']
            for em in a:
                if abs(a[em] - b.get(em, 0)) > 0.3:
                    return True
        return False

    def _make_contextual_observation(self, emotions):
        if not self.core:
            return
        try:
            full = defaultdict(float)
            total_intensity = 0
            for d in emotions:
                for k, v in d.get('expressions', {}).items():
                    w = v * d.get('intensity', 0.5)
                    full[k] += w
                    total_intensity += w

            if not full or total_intensity == 0:
                return

            for k in full:
                full[k] /= total_intensity

            dominant = max(full, key=full.get)
            strength = full[dominant]
            mood = self._map_emotion_to_mood(dominant)
            self.core.log_interaction(f"Visual observation: {dominant}", mood)
            if self.voice and hasattr(self.voice, 'enhanced_speak'):
                self.voice.enhanced_speak(f"I'm noticing some {dominant} energy.", dominant, strength)
            self.last_observation_time = time.time()
        except Exception as e:
            print(f"[VisionLink] Observation error: {e}")

    def _map_emotion_to_mood(self, emotion):
        mapping = {
            'happy': 'playful',
            'sad': 'calm',
            'angry': 'tense',
            'surprised': 'curious',
            'neutral': 'neutral',
            'fear': 'tense',
            'disgust': 'tense'
        }
        return mapping.get(emotion, 'neutral')"
}

